发现/source路径，访问后得到源码，然后进行代码审计
from flask import Flask, request, redirect, g, send_from_directory
import sqlite3
import os
import uuid  # 通用唯一识别码(Universally Unique Identifier)，标准格式为xxxxxxxx-xxxx-xxxx-xxxxxxxxxxxx

app &#x3D; Flask(__name__)

SCHEMA &#x3D; &quot;&quot;&quot;CREATE TABLE files (
id text primary key,
path text
);
&quot;&quot;&quot;


def db():
    g_db &#x3D; getattr(g, &#39;_database&#39;, None)
    if g_db is None:
        g_db &#x3D; g._database &#x3D; sqlite3.connect(&quot;database.db&quot;)
    return g_db


@app.before_first_request
def setup():  # 建立数据库连接
    os.remove(&quot;database.db&quot;)
    cur &#x3D; db().cursor()
    cur.executescript(SCHEMA)


@app.route(&#39;&#x2F;&#39;)
def hello_world():
    return &quot;&quot;&quot;&lt;!DOCTYPE html&gt;
&lt;html&gt;
&lt;body&gt;
&lt;form action&#x3D;&quot;&#x2F;upload&quot; method&#x3D;&quot;post&quot; enctype&#x3D;&quot;multipart&#x2F;form-data&quot;&gt;
    Select image to upload:
    &lt;input type&#x3D;&quot;file&quot; name&#x3D;&quot;file&quot;&gt;
    &lt;input type&#x3D;&quot;submit&quot; value&#x3D;&quot;Upload File&quot; name&#x3D;&quot;submit&quot;&gt;
&lt;&#x2F;form&gt;
&lt;!-- &#x2F;source --&gt;
&lt;&#x2F;body&gt;
&lt;&#x2F;html&gt;&quot;&quot;&quot;


@app.route(&#39;&#x2F;source&#39;)
def source():
    return send_from_directory(directory&#x3D;&quot;&#x2F;var&#x2F;www&#x2F;html&#x2F;&quot;, path&#x3D;&quot;www.zip&quot;, as_attachment&#x3D;True)


@app.route(&#39;&#x2F;upload&#39;, methods&#x3D;[&#39;POST&#39;])
def upload():
    if &#39;file&#39; not in request.files:
        return redirect(&#39;&#x2F;&#39;)
    file &#x3D; request.files[&#39;file&#39;]
    if &quot;.&quot; in file.filename:  # 检查上传的文件名是否含有点号，即过滤了后缀名
        return &quot;Bad filename!&quot;, 403
    conn &#x3D; db()
    cur &#x3D; conn.cursor()
    uid &#x3D; uuid.uuid4().hex  # 生成文件的uuid
    try:  # 检查文件是否重复
        cur.execute(&quot;insert into files (id, path) values (?, ?)&quot;, (uid, file.filename,))
    except sqlite3.IntegrityError:
        return &quot;Duplicate file&quot;
    conn.commit()

    file.save(&#39;uploads&#x2F;&#39; + file.filename)  # 保存文件在uploads&#x2F;下
    return redirect(&#39;&#x2F;file&#x2F;&#39; + uid)  # 返回文件的uuid


@app.route(&#39;&#x2F;file&#x2F;&lt;id&gt;&#39;)
def file(id):  # 访问文件
    conn &#x3D; db()
    cur &#x3D; conn.cursor()
    cur.execute(&quot;select path from files where id&#x3D;?&quot;, (id,))  # 根据文件uuid，在数据库中查询文件名
    res &#x3D; cur.fetchone()  # 将数据库查询结果返回
    if res is None:
        return &quot;File not found&quot;, 404

    # print(res[0])

    with open(os.path.join(&quot;uploads&#x2F;&quot;, res[0]), &quot;r&quot;) as f:  # 将查询到的文件名与uploads&#x2F;拼接
        return f.read()


if __name__ &#x3D;&#x3D; &#39;__main__&#39;:
    app.run(host&#x3D;&#39;0.0.0.0&#39;, port&#x3D;80)


综上，后端代码的逻辑如下：上传的文件不能有后缀名，上传后生成一个uuid，并将uuid和文件名存入数据库中，并返回文件的uuid。再通过/file/uuid访问文件，通过查询数据库得到对应文件名，在文件名前拼接uploads/后读取该路径下上传的文件。

但肯定要想如何读取 flag 文件，在文件名前被uploads/拼接意味着只能读取上传后的文件，而且上传的文件没有后缀名，不能直接利用，但os.path.join()函数存在绝对路径拼接漏洞









绝对路径拼接漏洞
os.path.join(path,*paths)函数用于将多个文件路径连接成一个组合的路径。第一个函数通常包含了基础路径，而之后的每个参数被当作组件拼接到基础路径之后。
然而，这个函数有一个少有人知的特性，如果拼接的某个路径以 &#x2F; 开头，那么包括基础路径在内的所有前缀路径都将被删除，该路径将视为绝对路径

由此，当上传的文件名为 &#x2F;flag ，上传后通过uuid访问文件后，查询到的文件名是 &#x2F;flag ，那么进行路径拼接时，uploads&#x2F; 将被删除，读取到的就是根目录下的 flag 文件。

使用BurpSuite抓包后，修改文件名为 &#x2F;flag 后发包，利用/file/uuid即可读取 flag。

